    features: [
      { title: "NATURAL STONE VENEER", description: "Thin-cut New England fieldstone, ledgestone, and bluestone veneer hand-applied over concrete, block, or wood-framed substrates." },
      { title: "MANUFACTURED STONE", description: "Cultured stone and cast veneers from Eldorado, Boral, and Dutch Quality that replicate natural stone at reduced weight and cost." },
      { title: "FOUNDATION FACING", description: "Covering exposed concrete foundations with stone veneer to dramatically improve your home's curb appeal and perceived value." },
      { title: "OUTDOOR KITCHEN SKINS", description: "Stone veneer applied to outdoor kitchen islands, bar faces, and grill surrounds for a high-end, integrated appearance." },
    ],
    includedDetails: [
      { title: "Substrate Preparation", description: "Proper veneer installation requires the right substrate. We prepare concrete, block, and wood-frame surfaces with appropriate scratch coats, lath, and moisture barriers to ensure the veneer bonds permanently and prevents water infiltration." },
      { title: "Material Selection", description: "We help you choose between natural thin-cut stone and manufactured alternatives. Natural stone provides authentic texture and color variation. Manufactured stone offers more consistent patterns and lighter weight for wood-frame applications." },
      { title: "Corner & Trim Work", description: "Corner pieces, window and door trim, and cap stones are the details that make veneer look like full-depth stone construction. We install pre-formed corner pieces and hand-cut trim stones for clean, professional transitions." },
      { title: "Water Management", description: "We install weep screed, moisture barriers, and proper flashing at the base and top of every veneer installation. These hidden elements prevent the water intrusion that causes veneer failure, staining, and structural damage." },
    ],
    processNote: "Free stone veneer consultations with material samples. We'll help you choose between natural and manufactured options.",
    ctaHeadline: "NEED STONE VENEER WORK?",
    metaTitle: "Stone Veneer Installation Wakefield, MA | New England Pavers & Stone",
    metaDescription: "Natural and manufactured stone veneer in Wakefield, MA. Foundation facing, outdoor kitchens, accent walls. Free estimates. Call (617) 697-3456.",
    faqItems: [
      { question: "Natural vs manufactured stone veneer — which is better?", answer: "Natural stone veneer provides authentic color, texture, and material depth that manufactured stone cannot fully replicate. Manufactured stone costs 20-30% less, weighs less (important for wood-frame applications), and offers more consistent patterning. The right choice depends on your application, budget, and aesthetic priorities." },
      { question: "How much does stone veneer cost in Massachusetts?", answer: "Stone veneer installation in the Greater Boston area typically costs $20-40 per square foot for manufactured stone and $30-55 per square foot for natural thin-cut stone. These prices include substrate prep, materials, and installation. We provide free detailed estimates." },
      { question: "Can you put stone veneer on a wood-framed wall?", answer: "Yes, with proper preparation. Wood-frame substrates require a moisture barrier, metal lath, and scratch coat before veneer installation. Manufactured stone is typically preferred for wood-frame applications due to its lighter weight. We handle all substrate preparation." },
      { question: "How long does stone veneer last?", answer: "Properly installed stone veneer lasts 50+ years. The key to longevity is correct substrate preparation and moisture management. Veneer failures are almost always caused by water infiltration behind the stone — not by the stone itself." },
      { question: "Can you match stone veneer to my existing stone work?", answer: "In most cases, we can find a natural or manufactured veneer that closely matches your existing stone features. We bring samples to your property for comparison in actual lighting conditions. Perfect matching of natural stone is difficult, but we achieve very close results." },
    ],
    benefits: [
      { title: "Transform Existing Surfaces", description: "Stone veneer converts plain concrete foundations, block walls, and stucco surfaces into natural-looking stone features. The visual transformation is dramatic and significantly impacts curb appeal." },
      { title: "Fraction of Full Stone Cost", description: "Thin-cut and manufactured veneers provide the appearance of full-depth stone at 40-60% of the cost. They also require no additional foundation support because they weigh a fraction of full stone." },
      { title: "Unified Design Language", description: "Stone veneer ties together different elements of your outdoor space — kitchen islands, retaining wall faces, foundation walls, and accent features all share the same stone appearance." },
      { title: "Increased Property Value", description: "Stone-faced foundations, outdoor kitchens, and accent features add perceived value and visual quality that buyers notice. Stone veneer is one of the highest-impact, moderate-cost exterior improvements available." },
    ],
    processSteps: [
      { title: "Consultation & Samples", description: "We visit your property, assess the surfaces to be veneered, and bring material samples for comparison. We discuss natural vs manufactured options and help you choose the stone that complements your home." },
      { title: "Substrate Preparation", description: "We prepare each surface with the appropriate moisture barrier, lath, and scratch coat. This preparation work is invisible in the finished product but is the foundation of a durable veneer installation." },
      { title: "Stone Installation", description: "Our masons hand-apply each stone piece, fitting corners, trim, and field stones for a natural appearance. Joints are grouted or dry-stacked depending on the stone style. The work is painstaking but the result is worth it." },
      { title: "Finishing & Protection", description: "We clean excess mortar, seal joints where appropriate, and install cap stones on wall tops. The completed veneer is inspected with you, and we provide care recommendations for long-term maintenance." },
    ],
